styles.css:
h1,
.wp-block-post-title {
	font-size: clamp(2.1rem, 1.8rem + 1.2vw, 2.8rem) !important;
	line-height: 1.08 !important;
}

.single-product :is(.wp-block-woocommerce-product-details, .woocommerce-Tabs-panel) .wp-block-group.testimonials,
.single-product .testimonials {
	background-color: #e8eef5 !important;
	border-left: 4px solid #195fa1 !important;
	display: block !important;
	margin: 32px 0 !important;
	padding: 32px !important;
}

.single-product :is(.wp-block-woocommerce-product-details, .woocommerce-Tabs-panel) .wp-block-group.testimonials :is(h3, .wp-block-heading),
.single-product .testimonials :is(h3, .wp-block-heading) {
	font-size: 1.75rem !important;
	line-height: 1.2 !important;
	margin: 0 0 20px !important;
}

.single-product :is(.wp-block-woocommerce-product-details, .woocommerce-Tabs-panel) .wp-block-group.testimonials p,
.single-product .testimonials p {
	font-size: 1.05rem !important;
	line-height: 1.7 !important;
	margin: 0 0 16px !important;
}

.single-product :is(.wp-block-woocommerce-product-details, .woocommerce-Tabs-panel) .wp-block-group.testimonials p:last-child,
.single-product .testimonials p:last-child {
	margin-bottom: 0 !important;
}

.single-product :is(.wp-block-woocommerce-product-details, .woocommerce-Tabs-panel) .wp-block-group:is(.bg-gold, .bg-pale-blue),
.single-product :is(.bg-gold, .bg-pale-blue) {
	border-radius: 2px !important;
	display: block !important;
	margin: 32px 0 !important;
	padding: 32px !important;
}

.single-product :is(.wp-block-woocommerce-product-details, .woocommerce-Tabs-panel) .wp-block-group.bg-gold,
.single-product .bg-gold {
	background-color: #ede4d8 !important;
}

.single-product :is(.wp-block-woocommerce-product-details, .woocommerce-Tabs-panel) .wp-block-group.bg-pale-blue,
.single-product .bg-pale-blue {
	background-color: #e8eef5 !important;
}

.single-product :is(.wp-block-woocommerce-product-details, .woocommerce-Tabs-panel) .wp-block-group:is(.bg-gold, .bg-pale-blue) :is(h2, h3, .wp-block-heading),
.single-product :is(.bg-gold, .bg-pale-blue) :is(h2, h3, .wp-block-heading) {
	color: #252018 !important;
	font-size: 1.75rem !important;
	line-height: 1.2 !important;
	margin: 0 0 20px !important;
}

.single-product :is(.wp-block-woocommerce-product-details, .woocommerce-Tabs-panel) .wp-block-group:is(.bg-gold, .bg-pale-blue) :is(p, li),
.single-product :is(.bg-gold, .bg-pale-blue) :is(p, li) {
	color: #4a4540 !important;
	font-size: 1.05rem !important;
	line-height: 1.7 !important;
}

.single-product :is(.wp-block-woocommerce-product-details, .woocommerce-Tabs-panel) .wp-block-group:is(.bg-gold, .bg-pale-blue) ul,
.single-product :is(.bg-gold, .bg-pale-blue) ul {
	margin: 0 0 18px 1.25rem !important;
}

.single-product :is(.wp-block-woocommerce-product-details, .woocommerce-Tabs-panel) .wp-block-group:is(.bg-gold, .bg-pale-blue) > *:first-child,
.single-product :is(.bg-gold, .bg-pale-blue) > *:first-child {
	margin-top: 0 !important;
}

.single-product :is(.wp-block-woocommerce-product-details, .woocommerce-Tabs-panel) .wp-block-group:is(.bg-gold, .bg-pale-blue) > *:last-child,
.single-product :is(.bg-gold, .bg-pale-blue) > *:last-child {
	margin-bottom: 0 !important;
}

.single-product .wp-block-woocommerce-related-products h2,
.single-product .wp-block-woocommerce-product-collection h2,
.single-product .wp-block-woocommerce-product-collection h2.wp-block-heading,
.single-product .related.products > h2 {
	font-size: 1.5rem !important;
	line-height: 1.2 !important;
	margin-bottom: 1rem !important;
}

.single-product .wp-block-woocommerce-related-products .wc-block-components-product-title,
.single-product .wp-block-woocommerce-product-collection .wc-block-components-product-title,
.single-product .related.products .woocommerce-loop-product__title {
	font-size: 1.05rem !important;
	font-weight: 600 !important;
	line-height: 1.35 !important;
}

.single-product .wp-block-woocommerce-related-products .wc-block-components-product-price,
.single-product .wp-block-woocommerce-product-collection .wc-block-components-product-price,
.single-product .related.products .price {
	font-size: 0.95rem !important;
}
